module synchronizer(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input data_in,
    input data_en,
    output dataout
);
// YOUR CODE HERE.
// BEGINNING OF INSTRUCTION
// Register data_reg
reg [3:0] data_reg;
always @(posedge clk_a or negedge rstn) begin
    if (!rstn) data_reg <= 4'b0;
    else data_reg <= data_in;
end
// Register en_data_reg
reg en_data_reg;
always @(posedge clk_a or negedge rstn) begin
    if (!rstn) en_data_reg <= 1'b0;
    else en_data_reg <= data_en;
end
// Registers en_clap_one and en_clap_two
reg en_clap_one;
reg en_clap_two;
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_one <= 1'b0;
        en_clap_two <= 1'b0;
    end
    else begin
        en_clap_one <= en_data_reg;
        en_clap_two <= en_clap_one;
    end
end
// Output assignment
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) dataout <= 4'b0;
    else if (en_clap_two) dataout <= data_reg;
    else dataout <= dataout;
end
// END OF INSTRUCTION
endmodule
